import { useVirtualizer } from '@tanstack/react-virtual';
import { useEffect, useRef, type ReactNode } from 'react';

import {
  TooltipItemsContainer,
  TooltipItems,
  StyledTooltipContainer,
  ScrollableContainerParent,
  DEFAULT_TOOLTIP_MIN_WIDTH,
  TOOLTIP_MAX_HEIGHT,
} from './InteractiveChartTooltip.styles.js';
import { Flex } from '../../../../../../layouts/flex/Flex.js';
import { useHandleSetScrollbar } from '../hooks/useHandleSetScrollbar.js';
import { VirtualEstimatedSize } from '../types/virtual-estimated-size.js';

interface ChartTooltipSeriesProps {
  pinned?: boolean;
  itemSize?: VirtualEstimatedSize;
  header?: ReactNode;
  body?: (() => ReactNode)[];
  pointerEvents: boolean;
  onScrollContent?: (event: Event) => void;
}

/**
 * Component handling how series are displayed inside the tooltip
 */
export const InteractiveChartTooltipVirtualizedSeries = (
  props: ChartTooltipSeriesProps,
) => {
  const { itemSize, header, body, pointerEvents, onScrollContent } = props;
  const scrollRef = useRef<HTMLDivElement>(null);
  const scrollRefContainer = useRef<HTMLDivElement>(null);

  const { getVirtualItems, getTotalSize, measureElement } = useVirtualizer({
    count: body?.length ?? 0,
    getScrollElement: () => scrollRefContainer.current,
    estimateSize: (index: number) => {
      return itemSize?.(index) ?? 16;
    },
    overscan: 3,
  });

  const items = getVirtualItems();

  useHandleSetScrollbar(getTotalSize());

  useEffect(() => {
    if (!onScrollContent) {
      return;
    }
    const scrollContainer = scrollRefContainer.current;
    scrollContainer?.addEventListener('scroll', onScrollContent);

    return () => {
      scrollContainer?.removeEventListener('scroll', onScrollContent);
    };
  }, [scrollRefContainer, onScrollContent]);

  // Calculate the min height of the container, in order to make sure that the
  // container can grow according to the content and not collapse recursively
  // with the virtualization.
  const containerMinHeight =
    typeof itemSize === 'undefined'
      ? Math.min((body?.length ?? 0) * 16, TOOLTIP_MAX_HEIGHT)
      : Math.min((body?.length ?? 0) * itemSize(0), TOOLTIP_MAX_HEIGHT);

  return (
    <StyledTooltipContainer
      minWidth={DEFAULT_TOOLTIP_MIN_WIDTH}
      allowPointerEvents={pointerEvents}
    >
      <Flex gap={0} flexDirection="column">
        {header}
        <ScrollableContainerParent
          ref={scrollRefContainer}
          data-testid="chart-tooltip-item-container"
          style={{
            minHeight: `clamp(${containerMinHeight}px, ${getTotalSize()}px, ${TOOLTIP_MAX_HEIGHT}px)`,
          }}
        >
          <TooltipItemsContainer
            ref={scrollRef}
            style={{
              height: getTotalSize(),
            }}
          >
            <div
              style={{
                transform: `translateY(${items[0]?.start ?? 0}px)`,
              }}
            >
              {items.map(({ index }) => {
                // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
                const CurrentVirtualizedItem = body![index];

                return (
                  <TooltipItems
                    data-testid="chart-tooltip-item"
                    key={index}
                    data-index={index}
                    ref={measureElement}
                  >
                    {CurrentVirtualizedItem()}
                  </TooltipItems>
                );
              })}
            </div>
          </TooltipItemsContainer>
        </ScrollableContainerParent>
      </Flex>
    </StyledTooltipContainer>
  );
};

InteractiveChartTooltipVirtualizedSeries['displayName'] =
  'InteractiveChartTooltipSeries';
